# Check if sides form (possibly degenerate) triangle
def is_triangle(a, b, c):
    s = (a + b + c) / 2
    return (a + b >= s) and (b + c >= s) and (a + c >= s)

# Non-degenerate case (all strict)
def is_strict_triangle(a, b, c):
    s = (a + b + c) / 2
    return (a + b > s) and (b + c > s) and (a + c > s)
